-- V2 任务模块（renwu）：主线任务 + 每日每周任务 + 用户进度
-- 执行示例: mysql -u root -p YOUR_DATABASE < server/db/migrations/v2_004_renwu.sql
-- 依赖: v2_yonghu_profiles

-- ═══════════════════════════════════════
-- 主线任务配置
-- ═══════════════════════════════════════
CREATE TABLE IF NOT EXISTS v2_renwu_config (
  id INT NOT NULL PRIMARY KEY,
  pretask_id INT NOT NULL DEFAULT 0 COMMENT '前置任务 ID，0=起始',
  type TINYINT NOT NULL DEFAULT 1 COMMENT '1=主线',
  taskname VARCHAR(100) DEFAULT '' COMMENT '任务名称',
  show_initial TINYINT NOT NULL DEFAULT 0 COMMENT '是否初始显示',
  tasktype TINYINT NOT NULL DEFAULT 0 COMMENT '1=升级 3=学堂 5=摇卦 6=祈福 7=运势',
  condition_value INT NOT NULL DEFAULT 0 COMMENT '达成条件数值',
  award_item_id INT NOT NULL DEFAULT 1001,
  award_num INT NOT NULL DEFAULT 1,
  icon INT NOT NULL DEFAULT 20001,
  forward INT NOT NULL DEFAULT 0 COMMENT '前往界面',
  open_level INT NOT NULL DEFAULT 1,
  end_level INT NOT NULL DEFAULT 100,
  KEY idx_tasktype (tasktype),
  KEY idx_pretask (pretask_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ═══════════════════════════════════════
-- 每日/每周任务配置
-- ═══════════════════════════════════════
CREATE TABLE IF NOT EXISTS v2_renwu_daily_config (
  id INT NOT NULL PRIMARY KEY,
  type TINYINT NOT NULL DEFAULT 1 COMMENT '1=每日 3=宝箱',
  name VARCHAR(50) NOT NULL DEFAULT '',
  icon INT NOT NULL DEFAULT 20001,
  tasktype INT NOT NULL DEFAULT 0 COMMENT '1-5=日常种类 99=每日宝箱 100=每周宝箱',
  condition_count INT NOT NULL DEFAULT 1 COMMENT '满足条件(完成次数/活跃累计)',
  reward_item_id INT NOT NULL DEFAULT 1001,
  reward_num INT NOT NULL DEFAULT 1,
  activity_point INT NOT NULL DEFAULT 0 COMMENT '完成后获得活跃点',
  open_level INT NOT NULL DEFAULT 0,
  end_level INT NOT NULL DEFAULT 0,
  forward INT NOT NULL DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ═══════════════════════════════════════
-- 用户主线进度
-- ═══════════════════════════════════════
CREATE TABLE IF NOT EXISTS v2_renwu_user_progress (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  quest_id INT NOT NULL COMMENT '关联 v2_renwu_config.id',
  completed TINYINT NOT NULL DEFAULT 0,
  claimed TINYINT NOT NULL DEFAULT 0,
  completed_at DATETIME DEFAULT NULL,
  claimed_at DATETIME DEFAULT NULL,
  UNIQUE KEY uk_user_quest (user_id, quest_id),
  CONSTRAINT fk_renwu_prog_user FOREIGN KEY (user_id) REFERENCES v2_yonghu_profiles(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ═══════════════════════════════════════
-- 用户每日/每周任务完成记录
-- ═══════════════════════════════════════
CREATE TABLE IF NOT EXISTS v2_renwu_user_daily (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  quest_config_id INT NOT NULL COMMENT '关联 v2_renwu_daily_config.id',
  period_key VARCHAR(16) NOT NULL COMMENT '如 2026-03-26 或 2026-W13',
  progress INT NOT NULL DEFAULT 0,
  completed TINYINT NOT NULL DEFAULT 0,
  claimed TINYINT NOT NULL DEFAULT 0,
  UNIQUE KEY uk_user_quest_period (user_id, quest_config_id, period_key),
  KEY idx_period (period_key),
  CONSTRAINT fk_renwu_daily_user FOREIGN KEY (user_id) REFERENCES v2_yonghu_profiles(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ═══════════════════════════════════════
-- 用户活跃值
-- ═══════════════════════════════════════
CREATE TABLE IF NOT EXISTS v2_renwu_user_activity (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  period_type VARCHAR(8) NOT NULL COMMENT 'daily 或 weekly',
  period_key VARCHAR(16) NOT NULL COMMENT '如 2026-03-26 或 2026-W13',
  points INT NOT NULL DEFAULT 0,
  UNIQUE KEY uk_user_period (user_id, period_type, period_key),
  CONSTRAINT fk_renwu_act_user FOREIGN KEY (user_id) REFERENCES v2_yonghu_profiles(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

